[
  {
    "httpMethod": "post",
    "operationId": "datasetsCreateDataset",
    "description": "Creates a new Dataset. A default branch - `master` for most enrollments - will be created on the Dataset.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsGetSchemaDatasetsBatch",
    "description": "Fetch schemas for multiple datasets in a single request. Datasets not found \nor inaccessible to the user will be omitted from the response.\n\n\nThe maximum batch size for this endpoint is 1000."
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsCreateView",
    "description": "Create a new View."
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetView",
    "description": "Get metadata for a View."
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsAddBackingDatasets",
    "description": "Adds one or more backing datasets to a View. Any duplicates with the same dataset RID and branch name are \nignored.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsAddPrimaryKey",
    "description": "Adds a primary key to a View that does not already have one. Primary keys are treated as \nguarantees provided by the creator of the dataset.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsRemoveBackingDatasets",
    "description": "Removes specified backing datasets from a View. Removing a dataset triggers a \n[SNAPSHOT](/docs/foundry/data-integration/datasets#snapshot) transaction on the next update. If a \nspecified dataset does not exist, no error is thrown.\n"
  },
  {
    "httpMethod": "put",
    "operationId": "datasetsReplaceBackingDatasets",
    "description": "Replaces the backing datasets for a View. Removing any backing dataset triggers a\n[SNAPSHOT](/docs/foundry/data-integration/datasets#snapshot) transaction the next time the View is updated.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetDataset",
    "description": "Get the Dataset with the specified rid."
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsListBranches",
    "description": "Lists the Branches of a Dataset.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsCreateBranch",
    "description": "Creates a branch on an existing dataset. A branch may optionally point to a (committed) transaction.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetBranch",
    "description": "Get a Branch of a Dataset.\n"
  },
  {
    "httpMethod": "delete",
    "operationId": "datasetsDeleteBranch",
    "description": "Deletes the Branch with the given BranchName.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetBranchTransactionHistory",
    "description": "Get the Transaction history for the given Dataset. When requesting all transactions, the endpoint returns them in reverse chronological order.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsListFiles",
    "description": "Lists Files contained in a Dataset. By default files are listed on the latest view of the default \nbranch - `master` for most enrollments.\n#### Advanced Usage\nSee [Datasets Core Concepts](/docs/foundry/data-integration/datasets/) for details on using branches and transactions.\nTo **list files on a specific Branch** specify the Branch's name as `branchName`. This will include the most\nrecent version of all files since the latest snapshot transaction, or the earliest ancestor transaction of the \nbranch if there are no snapshot transactions.\nTo **list files on the resolved view of a transaction** specify the Transaction's resource identifier\nas `endTransactionRid`. This will include the most recent version of all files since the latest snapshot\ntransaction, or the earliest ancestor transaction if there are no snapshot transactions.\nTo **list files on the resolved view of a range of transactions** specify the the start transaction's resource\nidentifier as `startTransactionRid` and the end transaction's resource identifier as `endTransactionRid`. This\nwill include the most recent version of all files since the `startTransactionRid` up to the `endTransactionRid`.\nNote that an intermediate snapshot transaction will remove all files from the view. Behavior is undefined when \nthe start and end transactions do not belong to the same root-to-leaf path.\nTo **list files on a specific transaction** specify the Transaction's resource identifier as both the \n`startTransactionRid` and `endTransactionRid`. This will include only files that were modified as part of that\nTransaction.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetFile",
    "description": "Gets metadata about a File contained in a Dataset. By default this retrieves the file's metadata from the latest\nview of the default branch - `master` for most enrollments.\n#### Advanced Usage\nSee [Datasets Core Concepts](/docs/foundry/data-integration/datasets/) for details on using branches and transactions. \nTo **get a file's metadata from a specific Branch** specify the Branch's name as `branchName`. This will \nretrieve metadata for the most recent version of the file since the latest snapshot transaction, or the earliest\nancestor transaction of the branch if there are no snapshot transactions.\nTo **get a file's metadata from the resolved view of a transaction** specify the Transaction's resource identifier\nas `endTransactionRid`. This will retrieve metadata for the most recent version of the file since the latest snapshot\ntransaction, or the earliest ancestor transaction if there are no snapshot transactions.\nTo **get a file's metadata from the resolved view of a range of transactions** specify the the start transaction's\nresource identifier as `startTransactionRid` and the end transaction's resource identifier as `endTransactionRid`.\nThis will retrieve metadata for the most recent version of the file since the `startTransactionRid` up to the \n`endTransactionRid`. Behavior is undefined when the start and end transactions do not belong to the same root-to-leaf path.\nTo **get a file's metadata from a specific transaction** specify the Transaction's resource identifier as both the \n`startTransactionRid` and `endTransactionRid`.\n"
  },
  {
    "httpMethod": "delete",
    "operationId": "datasetsDeleteFile",
    "description": "Deletes a File from a Dataset. By default the file is deleted in a new transaction on the default \nbranch - `master` for most enrollments. The file will still be visible on historical views.\n#### Advanced Usage\nSee [Datasets Core Concepts](/docs/foundry/data-integration/datasets/) for details on using branches and transactions.\nTo **delete a File from a specific Branch** specify the Branch's name as `branchName`. A new delete Transaction \nwill be created and committed on this branch.\nTo **delete a File using a manually opened Transaction**, specify the Transaction's resource identifier \nas `transactionRid`. The transaction must be of type `DELETE`. This is useful for deleting multiple files in a\nsingle transaction. See [createTransaction](/docs/foundry/api/datasets-resources/transactions/create-transaction/) to \nopen a transaction.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetFileContent",
    "description": "Gets the content of a File contained in a Dataset. By default this retrieves the file's content from the latest\nview of the default branch - `master` for most enrollments.\n#### Advanced Usage\nSee [Datasets Core Concepts](/docs/foundry/data-integration/datasets/) for details on using branches and transactions. \nTo **get a file's content from a specific Branch** specify the Branch's name as `branchName`. This will \nretrieve the content for the most recent version of the file since the latest snapshot transaction, or the\nearliest ancestor transaction of the branch if there are no snapshot transactions.\nTo **get a file's content from the resolved view of a transaction** specify the Transaction's resource identifier\nas `endTransactionRid`. This will retrieve the content for the most recent version of the file since the latest\nsnapshot transaction, or the earliest ancestor transaction if there are no snapshot transactions.\nTo **get a file's content from the resolved view of a range of transactions** specify the the start transaction's\nresource identifier as `startTransactionRid` and the end transaction's resource identifier as `endTransactionRid`.\nThis will retrieve the content for the most recent version of the file since the `startTransactionRid` up to the \n`endTransactionRid`. Note that an intermediate snapshot transaction will remove all files from the view. Behavior\nis undefined when the start and end transactions do not belong to the same root-to-leaf path.\nTo **get a file's content from a specific transaction** specify the Transaction's resource identifier as both the \n`startTransactionRid` and `endTransactionRid`.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsUploadFile",
    "description": "Uploads a File to an existing Dataset.\nThe body of the request must contain the binary content of the file and the `Content-Type` header must be `application/octet-stream`.\nBy default the file is uploaded to a new transaction on the default branch - `master` for most enrollments.\nIf the file already exists only the most recent version will be visible in the updated view.\n#### Advanced Usage\nSee [Datasets Core Concepts](/docs/foundry/data-integration/datasets/) for details on using branches and transactions. \nTo **upload a file to a specific Branch** specify the Branch's name as `branchName`. A new transaction will \nbe created and committed on this branch. By default the TransactionType will be `UPDATE`, to override this\ndefault specify `transactionType` in addition to `branchName`. \nSee [createBranch](/docs/foundry/api/datasets-resources/branches/create-branch/) to create a custom branch.\nTo **upload a file on a manually opened transaction** specify the Transaction's resource identifier as\n`transactionRid`. This is useful for uploading multiple files in a single transaction. \nSee [createTransaction](/docs/foundry/api/datasets-resources/transactions/create-transaction/) to open a transaction.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetDatasetHealthCheckReports",
    "description": "Get the most recent Data Health Check report for each check configured on the given Dataset.\nReturns one report per check, representing the current health status of the dataset.\n\nTo get the list of checks configured on a Dataset, use\n[Get Dataset Health Checks](/docs/foundry/api/datasets/get-dataset-health-checks/).\nFor the full report history of a specific check, use\n[Get Latest Check Reports](/docs/foundry/api/v2/data-health-v2-resources/checks/get-latest-check-reports).\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetDatasetHealthChecks",
    "description": "Get the RIDs of the Data Health Checks that are configured for the given Dataset.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetDatasetSchedules",
    "description": "Get the RIDs of the Schedules that target the given Dataset.\n\nNote: It may take up to an hour for recent changes to schedules to be reflected in this response,\nespecially for schedules managed by Marketplace. This operation will return outdated results in the\nmeantime.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetDatasetSchema",
    "description": "Gets a dataset's schema. If no `endTransactionRid` is provided, the latest committed version will be used.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsGetDatasetJobs",
    "description": "Get the RIDs of the Jobs for the given dataset. By default, returned Jobs are sorted in descending order by the Job start time.\n"
  },
  {
    "httpMethod": "put",
    "operationId": "datasetsPutDatasetSchema",
    "description": "Adds a schema on an existing dataset using a PUT request.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsReadTableDataset",
    "description": "Gets the content of a dataset as a table in the specified format.\n\nThis endpoint currently does not support views (virtual datasets composed of other datasets).\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsListTransactionsOfDataset",
    "description": "Get the Transaction history for the given Dataset. When requesting all transactions, the endpoint returns them in reverse chronological order.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsCreateTransaction",
    "description": "Creates a Transaction on a Branch of a Dataset.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "datasetsGetTransaction",
    "description": "Gets a Transaction of a Dataset.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsAbortTransaction",
    "description": "Aborts an open Transaction. File modifications made on this Transaction are not preserved and the Branch is\nnot updated.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "datasetsCommitTransaction",
    "description": "Commits an open Transaction. File modifications made on this Transaction are preserved and the Branch is\nupdated to point to the Transaction.\n"
  }
]

[
  {
    "httpMethod": "post",
    "operationId": "filesystemCreateFolder",
    "description": "Creates a new Folder."
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemGetFoldersBatch",
    "description": "Fetches multiple folders in a single request.\n\n\nThe maximum batch size for this endpoint is 1000."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemGetFolder",
    "description": "Get the Folder with the specified rid."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListChildrenOfFolder",
    "description": "List all child resources of the Folder.\n\nThis is a paged endpoint. The page size will be limited to 2,000 results per page. If no page size is\nprovided, this page size will also be used as the default.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemCreateProject",
    "description": "Creates a new Project.\n\nNote that third-party applications using this endpoint via OAuth2 cannot be associated with an\nOntology SDK as this will reduce the scope of operations to only those within specified projects.\nWhen creating the application, select \"No, I won't use an Ontology SDK\" on the Resources page.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemCreateProjectFromTemplate",
    "description": "Creates a project from a project template."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemGetProject",
    "description": "Get the Project with the specified rid."
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemAddOrganizations",
    "description": "Adds a list of Organizations to a Project."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListOrganizationsOfProject",
    "description": "List of Organizations directly applied to a Project. The number of Organizations on a Project is \ntypically small so the `pageSize` and `pageToken` parameters are not required.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListProjectResourceReferences",
    "description": "List all references in the given project\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemAddProjectResourceReferences",
    "description": "Add references to the given project\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemRemoveProjectResourceReferences",
    "description": "Remove references from the given project\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemRemoveOrganizations",
    "description": "Removes Organizations from a Project."
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemGetResourcesBatch",
    "description": "Fetches multiple resources in a single request.\nReturns a map from RID to the corresponding resource. If a resource does not exist, or if it is a root folder or space, its RID will not be included in the map.\nAt most 1,000 resources should be requested at once.\n\n\nThe maximum batch size for this endpoint is 1000."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemGetByPath",
    "description": "Get a resource by its absolute path."
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemGetByPathResourcesBatch",
    "description": "Gets multiple resources by their absolute paths.\nReturns a list of resources. If a path does not exist, is inaccessible, or refers to \na root folder or space, it will not be included in the response.\nAt most 1,000 paths should be requested at once.\n\n\nThe maximum batch size for this endpoint is 1000."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemGetResource",
    "description": "Get the Resource with the specified rid."
  },
  {
    "httpMethod": "delete",
    "operationId": "filesystemDeleteResource",
    "description": "Move the given resource to the trash. Following this operation, the resource can be restored, using the\n`restore` operation, or permanently deleted using the `permanentlyDelete` operation.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemAddMarkings",
    "description": "Adds a list of Markings to a resource."
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemGetAccessRequirements",
    "description": "Returns a list of access requirements a user needs in order to view a resource. Access requirements are\ncomposed of Organizations and Markings, and can either be applied directly to the resource or inherited.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListMarkingsOfResource",
    "description": "List of Markings directly applied to a resource. The number of Markings on a resource is typically small \nso the `pageSize` and `pageToken` parameters are not required.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemPermanentlyDeleteResource",
    "description": "Permanently delete the given resource from the trash. If the resource is not directly trashed, a\n`ResourceNotTrashed` error will be thrown.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemRemoveMarkings",
    "description": "Removes Markings from a resource."
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemRestoreResource",
    "description": "Restore the given resource and any directly trashed ancestors from the trash. If the resource is not\ntrashed, this operation will be ignored.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListResourceRoles",
    "description": "List the roles on a resource.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemAddResourceRoles"
  },
  {
    "httpMethod": "post",
    "operationId": "filesystemRemoveResourceRoles"
  },
  {
    "httpMethod": "get",
    "operationId": "filesystemListSpaces",
    "description": "Lists all Spaces.\n\nThis is a paged endpoint. Each page may be smaller or larger than the requested page size. However, it is guaranteed that if there are more results available, the `nextPageToken` field will be populated. To get the next page, make the same request again, but set the value of the `pageToken` query parameter to be value of the `nextPageToken` value of the previous response. If there is no `nextPageToken` field in the response, you are on the last page."
  }
]

[
  {
    "httpMethod": "post",
    "operationId": "orchestrationCreateBuild"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationGetBuildsBatch",
    "description": "Execute multiple get requests on Build.\n\nUsers are allowed to make a maximum of **4 requests per second** and **25 concurrent requests**.\n\n\nThe maximum batch size for this endpoint is 100."
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationGetBuild",
    "description": "Get the Build with the specified rid.\n\nUsers are allowed to make a maximum of **4 requests per second** and **25 concurrent requests**.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationCancelBuild",
    "description": "Request a cancellation for all unfinished jobs in a build. The build's status will not update immediately. This endpoint is asynchronous and a success response indicates that the cancellation request has been acknowledged and the build is expected to be canceled soon. If the build has already finished or finishes shortly after the request and before the cancellation, the build will not change.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationListJobsOfBuild",
    "description": "Get the Jobs in the Build."
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationGetJobsBatch",
    "description": "Execute multiple get requests on Job.\n\nUsers are allowed to make a maximum of **4 requests per second** and **25 concurrent requests**.\n\n\nThe maximum batch size for this endpoint is 500."
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationGetJob",
    "description": "Get the Job with the specified rid.\n\nUsers are allowed to make a maximum of **4 requests per second** and **25 concurrent requests**.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationGetScheduleVersion",
    "description": "Get the ScheduleVersion with the specified rid."
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationGetScheduleOfScheduleVersion"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationCreateSchedule",
    "description": "Creates a new Schedule.\n\n:::callout{theme=warning title=Warning}\nIf the schedule is created in user-scoped mode, outputs to build will be discovered based on resources\nthat the user has access to. If the user's permissions change later, this could change the outputs that\nwill be built or cause builds to fail. Consider using a project-scoped schedule instead.\n:::\n"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationGetSchedulesBatch",
    "description": "Fetch multiple schedules in a single request. Schedules not found or inaccessible to the user will be \nomitted from the response.\n\n\nThe maximum batch size for this endpoint is 1000."
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationGetSchedule",
    "description": "Get the Schedule with the specified rid."
  },
  {
    "httpMethod": "put",
    "operationId": "orchestrationReplaceSchedule",
    "description": "Replaces the Schedule with the specified rid.\n\n:::callout{theme=warning title=Warning}\nIf the schedule is configured in user-scoped mode, outputs to build will be discovered based on resources\nthat the user has access to. If the user's permissions change later, this could change the outputs that\nwill be built or cause builds to fail. Consider using a project-scoped schedule instead.\n:::\n"
  },
  {
    "httpMethod": "delete",
    "operationId": "orchestrationDeleteSchedule",
    "description": "Delete the Schedule with the specified rid."
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationGetAffectedResourcesSchedule"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationPauseSchedule"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationRunSchedule"
  },
  {
    "httpMethod": "get",
    "operationId": "orchestrationListRunsOfSchedule",
    "description": "Get the most recent runs of a Schedule. If no page size is provided, a page size of 100 will be used.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "orchestrationUnpauseSchedule"
  }
]

[
  {
    "httpMethod": "get",
    "operationId": "ontologiesListOntologiesV2",
    "description": "Lists the Ontologies visible to the current user.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesUploadAttachmentV2",
    "description": "Upload an attachment to use in an action. Any attachment which has not been linked to an object via\nan action within one hour after upload will be removed.\nPreviously mapped attachments which are not connected to any object anymore are also removed on\na biweekly basis.\nThe body of the request must contain the binary content of the file and the `Content-Type` header must be `application/octet-stream`.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetAttachmentV2",
    "description": "Get the metadata of an attachment.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetAttachmentContentV2",
    "description": "Get the content of an attachment.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetOntologyV2",
    "description": "Gets a specific ontology for a given Ontology API name or RID.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesListActionTypesV2",
    "description": "Lists the action types for the given Ontology.\n\nEach page may be smaller than the requested page size. However, it is guaranteed that if there are more\nresults available, at least one result will be present in the response.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetActionTypeByRid",
    "description": "Gets a specific action type with the given RID.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesGetActionTypeByRidBatch",
    "description": "Gets a list of action types by RID in bulk.\n\nAction types are filtered from the response if they don't exist or the requesting token lacks the required\npermissions.\n\nThe maximum batch size for this endpoint is 100.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetActionTypeV2",
    "description": "Gets a specific action type with the given API name.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesApplyActionV2",
    "description": "Applies an action using the given parameters. \n\nChanges to objects or links stored in Object Storage V1 are eventually consistent and may take some time to be visible.\nEdits to objects or links in Object Storage V2 will be visible immediately after the action completes.\n\nNote that a 200 HTTP status code only indicates that the request was received and processed by the server. \nSee the validation result in the response body to determine if the action was applied successfully.\n\nNote that [parameter default values](/docs/foundry/action-types/parameters-default-value/) are not currently supported by\nthis endpoint.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesApplyActionBatchV2",
    "description": "Applies multiple actions (of the same Action Type) using the given parameters.\n\nChanges to objects or links stored in Object Storage V1 are eventually consistent and may take some time to be visible.\nEdits to objects or links in Object Storage V2 will be visible immediately after the action completes.\n\nUp to 20 actions may be applied in one call. Actions that only modify objects in Object Storage v2 and do not\ncall Functions may receive a higher limit.\n\nNote that [notifications](/docs/foundry/action-types/notifications/) are not currently supported by this endpoint.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetOntologyFullMetadata",
    "description": "Get the full Ontology metadata. This includes the objects, links, actions, queries, and interfaces.\nThis endpoint is designed to return as much metadata as possible in a single request to support OSDK workflows.\nIt may omit certain entities rather than fail the request.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesListInterfaceTypes",
    "description": "Lists the interface types for the given Ontology.\n\nEach page may be smaller than the requested page size. However, it is guaranteed that if there are more\nresults available, at least one result will be present in the response.\n"
  },
  {
    "httpMethod": "get",
    "operationId": "ontologiesGetInterfaceType",
    "description": "Gets a specific interface type with the given API name.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesAggregateObjectSetV2",
    "description": "Aggregates the ontology objects present in the `ObjectSet` from the provided object set definition.\n"
  },
  {
    "httpMethod": "post",
    "operationId": "ontologiesCreateTemporaryObjectSetV2",
    "description": "Creates a temporary `ObjectSet` from the given definition. This `ObjectSet` expires after one hour.\n"
  },
  {
